package org.apache.commons.math3.analysis.differentiation;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.math3.analysis.differentiation.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math3.analysis.differentiation.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.analysis.differentiation.DerivativeStructure;

import static org.junit.Assert.assertEquals;

public class StepDefs {

    private DerivativeStructure y;
    private DerivativeStructure x;
    private DerivativeStructure result;

    @Given("a DerivativeStructure \"y\" constructed with value {double}")
    public void a_DerivativeStructure_y_constructed_with_value(double y_val) {
        y = new DerivativeStructure(1, 0, y_val); // 1 parameter, order 0, value y_val
    }

    @Given("a DerivativeStructure \"x\" constructed with value {double}")
    public void a_DerivativeStructure_x_constructed_with_value(double x_val) {
        x = new DerivativeStructure(1, 0, x_val); // 1 parameter, order 0, value x_val
    }

    @When("the method \"atan2\" is invoked with \"y\" and \"x\"")
    public void the_method_atan2_is_invoked_with_y_and_x() {
        try {
            result = DerivativeStructure.atan2(y, x);
        } catch (Exception e) {
            // Store the exception for later checking if needed
            System.out.println("Exception occurred: " + e.getMessage());
        }
    }

    @Then("the value of the resulting DerivativeStructure should be {double}")
    public void the_value_of_the_resulting_DerivativeStructure_should_be(double expected_result) {
        // Using a small tolerance for floating point comparison
        assertEquals(expected_result, result.getValue(), 1e-15);
    }

    @Then("the sign of the value should be {double}")
    public void the_sign_of_the_value_should_be(double expected_sign) {
        double actualValue = result.getValue();
        double actualSign = Math.signum(actualValue);
        assertEquals(expected_sign, actualSign, 1e-15);
    }
}

